"use strict";(globalThis.webpackChunkcallums_lab=globalThis.webpackChunkcallums_lab||[]).push([[8130],{7735(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"why-this-blog-exists","metadata":{"permalink":"/blog/why-this-blog-exists","source":"@site/blog/2026-03-20-blog-template.md","title":"Why This Blog Exists","description":"This blog is for writing that deserves a more public form than the notes in the docs section.","date":"2026-03-20T00:00:00.000Z","tags":[{"inline":false,"label":"Security","permalink":"/blog/tags/security","description":"Security research, writeups, and practical notes"}],"readingTime":0.65,"hasTruncateMarker":true,"authors":[{"name":"Callum H. Xu","title":"Security Researcher | Founder of JoyX","url":"/about","page":null,"socials":{"x":"https://x.com/0xca1x","github":"https://github.com/0xca1x","joyx":"https://joyx.io/"},"imageURL":"/img/callum.jpeg","key":"callum"}],"frontMatter":{"slug":"why-this-blog-exists","title":"Why This Blog Exists","authors":"callum","tags":["security"]},"unlisted":false},"content":"This blog is for writing that deserves a more public form than the notes in the docs section.\\n\\nMost of the site is a working research base: narrower notes, study material, references, and write-ups kept close to the original work. The blog is where that material gets distilled into something more readable for a broader audience.\\n\\n\x3c!-- truncate --\x3e\\n\\nI expect most posts here to fall into a few categories:\\n\\n- research summaries worth reading on their own\\n- vulnerability analysis and case studies\\n- write-ups on methods, tooling, and review practice\\n- occasional reflections on how I approach technical work\\n\\nThe standard is simple:\\n\\n- explain the problem clearly\\n- keep examples concrete\\n- leave the reader with something reusable\\n\\nThe goal is not to publish often. The goal is to publish things worth revisiting."}]}}')}}]);